from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a building into a single fluent complex sentence.
    """
    if not triples:
        return ""

    # Find the main subject - the one that appears most as subject in building-related predicates
    subject_counts = {}
    for t in triples:
        if t.subject not in subject_counts:
            subject_counts[t.subject] = 0
        subject_counts[t.subject] += 1

    # Prefer the subject that has building-related predicates
    building_predicates = {'architect', 'architecturalStyle', 'floorCount', 'height', 'buildingType',
                          'cost', 'owner', 'developer', 'tenant', 'currentTenants', 'numberOfRooms',
                          'bedCount', 'floorArea', 'location', 'address', 'formerName', 'completionDate',
                          'inaugurationDate', 'yearOfConstruction', 'buildingStartDate'}

    main_subject = None
    max_score = -1
    for subj, count in subject_counts.items():
        subj_score = count
        for t in triples:
            if t.subject == subj and t.predicate in building_predicates:
                subj_score += 2
        if subj_score > max_score:
            max_score = subj_score
            main_subject = subj

    if main_subject is None:
        main_subject = triples[0].subject

    # Collect all information into a structured format
    entity_data = {}  # entity_name -> {predicate: object}
    location_hierarchy = []  # List of (location, country_info) tuples
    main_building_info = {}

    for t in triples:
        if t.subject not in entity_data:
            entity_data[t.subject] = {}
        entity_data[t.subject][t.predicate] = t.object

        if t.subject == main_subject:
            main_building_info[t.predicate] = t.object

    # Build location chain by following isPartOf/country/state/region/location predicates
    visited = set()
    current = main_subject

    while current and current not in visited:
        visited.add(current)
        if current in entity_data:
            for pred in ['location', 'isPartOf', 'state', 'region', 'country']:
                if pred in entity_data[current]:
                    loc = entity_data[current][pred]
                    location_hierarchy.append((loc, current, pred))
                    current = loc
                    break
            else:
                break
        else:
            break

    # Build the sentence with proper clause structure
    sentence_parts = []
    relative_clauses = []

    # Start with main subject
    if 'buildingType' in main_building_info:
        sentence_parts.append(f"{main_subject} is a {main_building_info['buildingType']}")
    else:
        sentence_parts.append(main_subject)

    # Add architect with optional birth place
    if 'architect' in main_building_info:
        architect = main_building_info['architect']
        if architect in entity_data and 'birthPlace' in entity_data[architect]:
            relative_clauses.append(f"designed by {architect}, who was born in {entity_data[architect]['birthPlace']}")
        else:
            relative_clauses.append(f"designed by {architect}")

    # Add architectural style
    if 'architecturalStyle' in main_building_info:
        relative_clauses.append(f"featuring {main_building_info['architecturalStyle']} architecture")

    # Add physical characteristics
    if 'floorCount' in main_building_info:
        relative_clauses.append(f"with {main_building_info['floorCount']} floors")
    if 'height' in main_building_info:
        relative_clauses.append(f"standing {main_building_info['height']} in height")
    if 'numberOfRooms' in main_building_info:
        relative_clauses.append(f"containing {main_building_info['numberOfRooms']} rooms")
    if 'bedCount' in main_building_info:
        relative_clauses.append(f"with {main_building_info['bedCount']} beds")
    if 'floorArea' in main_building_info:
        relative_clauses.append(f"covering {main_building_info['floorArea']} in floor area")

    # Add financial/ownership info
    if 'cost' in main_building_info:
        relative_clauses.append(f"at a cost of {main_building_info['cost']}")
    if 'owner' in main_building_info:
        relative_clauses.append(f"owned by {main_building_info['owner']}")
    if 'developer' in main_building_info:
        relative_clauses.append(f"developed by {main_building_info['developer']}")
    if 'tenant' in main_building_info:
        relative_clauses.append(f"tenanted by {main_building_info['tenant']}")
    if 'currentTenants' in main_building_info:
        relative_clauses.append(f"currently housing {main_building_info['currentTenants']}")

    # Add temporal information
    if 'completionDate' in main_building_info:
        relative_clauses.append(f"completed in {main_building_info['completionDate']}")
    if 'inaugurationDate' in main_building_info:
        relative_clauses.append(f"inaugurated on {main_building_info['inaugurationDate']}")
    if 'yearOfConstruction' in main_building_info:
        relative_clauses.append(f"built in {main_building_info['yearOfConstruction']}")
    if 'buildingStartDate' in main_building_info:
        relative_clauses.append(f"construction began in {main_building_info['buildingStartDate']}")

    # Add address if available
    if 'address' in main_building_info:
        relative_clauses.append(f"at {main_building_info['address']}")

    # Add former name if available
    if 'formerName' in main_building_info:
        relative_clauses.append(f"formerly known as {main_building_info['formerName']}")

    # Build location chain with country information
    if location_hierarchy:
        location_parts = []
        for i, (loc, _, _) in enumerate(location_hierarchy):
            if i == 0:
                location_parts.append(f"located in {loc}")
            else:
                location_parts.append(f"which is in {loc}")
        relative_clauses.extend(location_parts)

    # Combine main parts and relative clauses
    all_parts = sentence_parts + relative_clauses

    # Join all parts into a single fluent sentence
    if len(all_parts) == 1:
        sentence = all_parts[0]
    else:
        sentence = all_parts[0]
        for part in all_parts[1:]:
            sentence += ", " + part

    # Ensure proper capitalization and punctuation
    sentence = sentence[0].upper() + sentence[1:]
    if not sentence.endswith('.'):
        sentence += '.'

    return sentence

# EVOLVE-BLOCK-END

